#!/usr/bin/env bash

set -euo pipefail

# =============================================================================
# AWS Deployment Script
# Supports both local development and CI/CD environments
# =============================================================================

# Color codes for output
readonly RED='\033[0;31m'
readonly GREEN='\033[0;32m'
readonly YELLOW='\033[1;33m'
readonly BLUE='\033[0;34m'
readonly NC='\033[0m' # No Color

# Default configuration
readonly SCRIPT_NAME="$(basename "$0")"
readonly TIMESTAMP="$(date +%Y%m%d%H%M%S)"
readonly LOG_FILE="/tmp/aws-deploy-${TIMESTAMP}.log"

# Deployment defaults
DEFAULT_REGION="us-east-1"
DEFAULT_ENVIRONMENT="staging"
DEFAULT_STACK_NAME=""
DEFAULT_S3_BUCKET=""
DEFAULT_ECR_REPO=""
DEFAULT_ECS_CLUSTER=""
DEFAULT_ECS_SERVICE=""
DEFAULT_LAMBDA_FUNCTION=""
DEPLOY_TYPE=""
DRY_RUN=false
FORCE=false
ROLLBACK_ON_FAILURE=true
HEALTH_CHECK_RETRIES=30
HEALTH_CHECK_INTERVAL=10

# =============================================================================
# Logging Functions
# =============================================================================

log() {
    local level="$1"
    shift
    local message="$*"
    local timestamp
    timestamp="$(date '+%Y-%m-%d %H:%M:%S')"
    echo -e "${timestamp} [${level}] ${message}" | tee -a "${LOG_FILE}"
}

info() {
    log "INFO" "${GREEN}$*${NC}"
}

warn() {
    log "WARN" "${YELLOW}$*${NC}"
}

error() {
    log "ERROR" "${RED}$*${NC}"
}

debug() {
    if [[ "${VERBOSE:-false}" == "true" ]]; then
        log "DEBUG" "${BLUE}$*${NC}"
    fi
}

# =============================================================================
# Usage and Help
# =============================================================================

usage() {
    cat <<EOF
Usage: ${SCRIPT_NAME} [OPTIONS]

AWS Deployment Script - Deploy applications to AWS services

OPTIONS:
    -t, --type TYPE           Deployment type: s3, ecs, lambda, cloudformation, eb (required)
    -e, --environment ENV     Target environment: dev, staging, production (default: ${DEFAULT_ENVIRONMENT})
    -r, --region REGION       AWS region (default: ${DEFAULT_REGION})
    -p, --profile PROFILE     AWS CLI profile name (for local development)
    -s, --stack-name NAME     CloudFormation stack name
    -b, --bucket BUCKET       S3 bucket name (for S3 deployments)
    --ecr-repo REPO           ECR repository name
    --ecs-cluster CLUSTER     ECS cluster name
    --ecs-service SERVICE     ECS service name
    --lambda-function FUNC    Lambda function name
    --source-dir DIR          Source directory for deployment artifacts
    --template FILE           CloudFormation template file
    --params-file FILE        CloudFormation parameters file
    --docker-file FILE        Dockerfile path (default: ./Dockerfile)
    --image-tag TAG           Docker image tag (default: git SHA or timestamp)
    --dry-run                 Perform a dry run without making changes
    --force                   Skip confirmation prompts
    --no-rollback             Disable automatic rollback on failure
    --verbose                 Enable verbose output
    -h, --help                Show this help message

ENVIRONMENT VARIABLES:
    AWS_ACCESS_KEY_ID         AWS access key (CI/CD)
    AWS_SECRET_ACCESS_KEY     AWS secret key (CI/CD)
    AWS_SESSION_TOKEN         AWS session token (optional, for assumed roles)
    AWS_DEFAULT_REGION        Default AWS region
    AWS_PROFILE               AWS CLI profile name
    DEPLOY_ENVIRONMENT        Target environment
    CI                        Set to 'true' in CI/CD environments

EXAMPLES:
    # Deploy to S3 (static website)
    ${SCRIPT_NAME} -t s3 -b my-website-bucket --source-dir ./build -e production

    # Deploy to ECS (container service)
    ${SCRIPT_NAME} -t ecs --ecs-cluster my-cluster --ecs-service my-service --ecr-repo my-repo

    # Deploy Lambda function
    ${SCRIPT_NAME} -t lambda --lambda-function my-function --source-dir ./dist

    # Deploy CloudFormation stack
    ${SCRIPT_NAME} -t cloudformation -s my-stack --template template.yaml --params-file params.json

    # Dry run for production
    ${SCRIPT_NAME} -t ecs --ecs-cluster prod-cluster --ecs-service api -e production --dry-run
EOF
    exit 0
}

# =============================================================================
# Utility Functions
# =============================================================================

cleanup() {
    local exit_code=$?
    if [[ ${exit_code} -ne 0 ]]; then
        error "Deployment failed with exit code ${exit_code}"
        error "Check log file: ${LOG_FILE}"
        if [[ "${ROLLBACK_ON_FAILURE}" == "true" && "${DRY_RUN}" == "false" ]]; then
            warn "Attempting rollback..."
            perform_rollback || error "Rollback failed!"
        fi
    fi
    # Clean up temporary files
    rm -f /tmp/aws-deploy-params-*.json 2>/dev/null || true
    exit ${exit_code}
}

trap cleanup EXIT
trap 'error "Script interrupted"; exit 130' INT TERM

is_ci_environment() {
    [[ "${CI:-false}" == "true" ]] || \
    [[ -n "${GITHUB_ACTIONS:-}" ]] || \
    [[ -n "${GITLAB_CI:-}" ]] || \
    [[ -n "${JENKINS_URL:-}" ]] || \
    [[ -n "${CIRCLECI:-}" ]] || \
    [[ -n "${CODEBUILD_BUILD_ID:-}" ]] || \
    [[ -n "${BITBUCKET_PIPELINE_UUID:-}" ]] || \
    [[ -n "${TRAVIS:-}" ]]
}

confirm_action() {
    local message="$1"
    if [[ "${FORCE}" == "true" ]] || is_ci_environment; then
        return 0
    fi
    echo -e "${YELLOW}${message}${NC}"
    read -rp "Continue? (y/N): " response
    [[ "${response}" =~ ^[Yy]$ ]]
}

get_git_sha() {
    if command -v git &>/dev/null && git rev-parse --git-dir &>/dev/null; then
        git rev-parse --short HEAD 2>/dev/null || echo "${TIMESTAMP}"
    else
        echo "${TIMESTAMP}"
    fi
}

get_git_branch() {
    if command -v git &>/dev/null && git rev-parse --git-dir &>/dev/null; then
        git rev-parse --abbrev-ref HEAD 2>/dev/null || echo "unknown"
    else
        echo "unknown"
    fi
}

mask_secret() {
    local value="$1"
    if [[ ${#value} -le 8 ]]; then
        echo "****"
    else
        echo "${value:0:4}****${value: -4}"
    fi
}

# =============================================================================
# AWS Authentication and Validation
# =============================================================================

check_prerequisites() {
    info "Checking prerequisites..."

    # Check AWS CLI
    if ! command -v aws &>/dev/null; then
        error "AWS CLI is not installed. Please install it first."
        error "Visit: https://docs.aws.amazon.com/cli/latest/userguide/getting-started-install.html"
        exit 1
    fi

    local aws_version
    aws_version="$(aws --version 2>&1)"
    debug "AWS CLI version: ${aws_version}"

    # Check jq for JSON processing
    if ! command -v jq &>/dev/null; then
        error "jq is not installed. Please install it (e.g., apt-get install jq / brew install jq)"
        exit 1
    fi

    # Check deployment-type specific prerequisites
    case "${DEPLOY_TYPE}" in
        ecs)
            if ! command -v docker &>/dev/null; then
                error "Docker is not installed. Required for ECS deployments."
                exit 1
            fi
            ;;
        lambda)
            if ! command -v zip &>/dev/null; then
                error "zip is not installed. Required for Lambda deployments."
                exit 1
            fi
            ;;
    esac

    info "Prerequisites check passed."
}

configure_aws_auth() {
    info "Configuring AWS authentication..."

    # Set region
    export AWS_DEFAULT_REGION="${AWS_REGION:-${DEFAULT_REGION}}"
    info "Using AWS region: ${AWS_DEFAULT_REGION}"

    if is_ci_environment; then
        info "CI/CD environment detected."

        # In CI/CD, expect environment variables or IAM role
        if [[ -n "${AWS_ACCESS_KEY_ID:-}" ]] && [[ -n "${AWS_SECRET_ACCESS_KEY:-}" ]]; then
            info "Using AWS access key: $(mask_secret "${AWS_ACCESS_KEY_ID}")"
            if [[ -n "${AWS_SESSION_TOKEN:-}" ]]; then
                info "AWS session token is set (assumed role)"
            fi
        elif [[ -n "${AWS_ROLE_ARN:-}" ]]; then
            info "Assuming IAM role: ${AWS_ROLE_ARN}"
            assume_role "${AWS_ROLE_ARN}" "${AWS_ROLE_SESSION_NAME:-deploy-session}"
        else
            info "No explicit credentials found. Using instance/task role or environment defaults."
        fi
    else
        # Local development
        if [[ -n "${AWS_PROFILE:-}" ]]; then
            info "Using AWS profile: ${AWS_PROFILE}"
            export AWS_PROFILE
        elif [[ -n "${AWS_ACCESS_KEY_ID:-}" ]]; then
            info "Using AWS access key from environment"
        else
            warn "No AWS credentials configured. Attempting to use default profile."
            if [[ -f "${HOME}/.aws/credentials" ]] || [[ -f "${HOME}/.aws/config" ]]; then
                info "Found AWS configuration files."
            else
                error "No AWS credentials found. Configure with 'aws configure' or set environment variables."
                exit 1
            fi
        fi

        # Support for AWS SSO
        if aws configure get sso_start_url --profile "${AWS_PROFILE:-default}" &>/dev/null 2>&1; then
            info "AWS SSO profile detected. Ensuring SSO session is active..."
            if ! aws sts get-caller-identity &>/dev/null 2>&1; then
                warn "SSO session expired. Initiating login..."
                aws sso login --profile "${AWS_PROFILE:-default}"
            fi
        fi
    fi

    # Validate authentication
    validate_aws_auth
}

assume_role() {
    local role_arn="$1"
    local session_name="$2"

    info "Assuming role: ${role_arn}"

    local credentials
    credentials=$(aws sts assume-role \
        --role-arn "${role_arn}" \
        --role-session-name "${session_name}" \
        --duration-seconds 3600 \
        --output json 2>&1)

    if [[ $? -ne 0 ]]; then
        error "Failed to assume role: ${credentials}"
        exit 1
    fi

    export AWS_ACCESS_KEY_ID
    export AWS_SECRET_ACCESS_KEY
    export AWS_SESSION_TOKEN
    AWS_ACCESS_KEY_ID=$(echo "${credentials}" | jq -r '.Credentials.AccessKeyId')
    AWS_SECRET_ACCESS_KEY=$(echo "${credentials}" | jq -r '.Credentials.SecretAccessKey')
    AWS_SESSION_TOKEN=$(echo "${credentials}" | jq -r '.Credentials.SessionToken')

    info "Successfully assumed role. Session expires: $(echo "${credentials}" | jq -r '.Credentials.Expiration')"
}

validate_aws_auth() {
    info "Validating AWS credentials..."

    local identity
    identity=$(aws sts get-caller-identity --output json 2>&1)

    if [[ $? -ne 0 ]]; then
        error "AWS authentication failed: ${identity}"
        error "Please check your credentials and try again."
        exit 1
    fi

    local account_id arn
    account_id=$(echo "${identity}" | jq -r '.Account')
    arn=$(echo "${identity}" | jq -r '.Arn')

    info "Authenticated as: ${arn}"
    info "AWS Account: ${account_id}"

    # Safety check: warn if deploying to production
    if [[ "${ENVIRONMENT}" == "production" ]]; then
        warn "⚠️  WARNING: You are deploying to PRODUCTION (Account: ${account_id})"
        if ! confirm_action "Are you sure you want to deploy to production?"; then
            error "Deployment cancelled by user."
            exit 1
        fi
    fi
}

# =============================================================================
# S3 Deployment
# =============================================================================

deploy_s3() {
    local bucket="${S3_BUCKET}"
    local source_dir="${SOURCE_DIR:-.}"

    if [[ -z "${bucket}" ]]; then
        error "S3 bucket name is required. Use -b or --bucket option."
        exit 1
    fi

    if [[ ! -d "${source_dir}" ]]; then
        error "Source directory does not exist: ${source_dir}"
        exit 1
    fi

    info "Deploying to S3 bucket: ${bucket}"
    info "Source directory: ${source_dir}"

    # Check if bucket exists
    if ! aws s3api head-bucket --bucket "${bucket}" 2>/dev/null; then
        error "S3 bucket '${bucket}' does not exist or you don't have access."
        exit 1
    fi

    local sync_args=(
        "${source_dir}"
        "s3://${bucket}"
        "--delete"
    )

    # Add cache control headers for common file types
    local extra_args=()
    extra_args+=("--cache-control" "max-age=31536000,public")

    if [[ "${DRY_RUN}" == "true" ]]; then
        sync_args+=("--dryrun")
        info "[DRY RUN] Would sync files to s3://${bucket}"
    fi

    # Sync files
    info "Syncing files to S3..."
    aws s3 sync "${sync_args[@]}" 2>&1 | tee -a "${LOG_FILE}"

    if [[ "${DRY_RUN}" == "false" ]]; then
        # Upload HTML files with no-cache
        info "Setting cache headers for HTML files..."
        aws s3 cp "${source_dir}" "s3://${bucket}" \
            --recursive \
            --exclude "*" \
            --include "*.html" \
            --cache-control "no-cache,no-store,must-revalidate" \
            --content-type "text/html" 2>&1 | tee -a "${LOG_FILE}"

        # Invalidate CloudFront distribution if configured
        invalidate_cloudfront "${bucket}"
    fi

    info "S3 deployment completed successfully!"
}

invalidate_cloudfront() {
    local bucket="$1"

    # Find CloudFront distribution for this bucket
    local distributions
    distributions=$(aws cloudfront list-distributions --output json 2>/dev/null)

    if [[ $? -ne 0 ]] || [[ -z "${distributions}" ]]; then
        debug "No CloudFront distributions found or unable to list."
        return 0
    fi

    local dist_id
    dist_id=$(echo "${distributions}" | jq -r \
        ".DistributionList.Items[]? | select(.Origins.Items[]?.DomainName | contains(\"${bucket}\")) | .Id" \
        2>/dev/null | head -1)

    if [[ -n "${dist_id}" && "${dist_id}" != "null" ]]; then
        info "Found CloudFront distribution: ${dist_id}"
        info "Creating cache invalidation..."

        local invalidation_id
        invalidation_id=$(aws cloudfront create-invalidation \
            --distribution-id "${dist_id}" \
            --paths "/*" \
            --output json 2>&1 | jq -r '.Invalidation.Id')

        if [[ -n "${invalidation_id}" && "${invalidation_id}" != "null" ]]; then
            info "CloudFront invalidation created: ${invalidation_id}"
        else
            warn "Failed to create CloudFront invalidation."
        fi
    else
        debug "No CloudFront distribution found for bucket: ${bucket}"
    fi
}

# =============================================================================
# ECS Deployment
# =============================================================================

deploy_ecs() {
    local cluster="${ECS_CLUSTER}"
    local service="${ECS_SERVICE}"
    local ecr_repo="${ECR_REPO}"
    local dockerfile="${DOCKER_FILE:-./Dockerfile}"
    local image_tag="${IMAGE_TAG:-$(get_git_sha)}"

    if [[ -z "${cluster}" ]] || [[ -z "${service}" ]] || [[ -z "${ecr_repo}" ]]; then
        error "ECS deployment requires --ecs-cluster, --ecs-service, and --ecr-repo options."
        exit 1
    fi

    if [[ ! -f "${dockerfile}" ]]; then
        error "Dockerfile not found: ${dockerfile}"
        exit 1
    fi

    info "ECS Deployment Configuration:"
    info "  Cluster:    ${cluster}"
    info "  Service:    ${service}"
    info "  ECR Repo:   ${ecr_repo}"
    info "  Image Tag:  ${image_tag}"
    info "  Dockerfile: ${dockerfile}"

    if [[ "${DRY_RUN}" == "true" ]]; then
        info "[DRY RUN] Would deploy to ECS cluster '${cluster}', service '${service}'"
        return 0
    fi

    # Get ECR login
    info "Authenticating with ECR..."
    local account_id
    account_id=$(aws sts get-caller-identity --query Account --output text)
    local ecr_uri="${account_id}.dkr.ecr.${AWS_DEFAULT_REGION}.amazonaws.com"

    aws ecr get-login-password --region "${AWS_DEFAULT_REGION}" | \
        docker login --username AWS --password-stdin "${ecr_uri}" 2>&1 | tee -a "${LOG_FILE}"

    # Ensure ECR repository exists
    aws ecr describe-repositories --repository-names "${ecr_repo}" &>/dev/null || {
        info "Creating ECR repository: ${ecr_repo}"
        aws ecr create-repository \
            --repository-name "${ecr_repo}" \
            --image-scanning-configuration scanOnPush=true \
            --encryption-configuration encryptionType=AES256 2>&1 | tee -a "${LOG_FILE}"
    }

    local full_image="${ecr_uri}/${ecr_repo}:${image_tag}"

    # Build Docker image
    info "Building Docker image: ${full_image}"
    docker build \
        -t "${full_image}" \
        -t "${ecr_uri}/${ecr_repo}:latest" \
        -f "${dockerfile}" \
        --build-arg BUILD_ENV="${ENVIRONMENT}" \
        --build-arg BUILD_TIMESTAMP="${TIMESTAMP}" \
        . 2>&1 | tee -a "${LOG_FILE}"

    # Push Docker image
    info "Pushing Docker image to ECR..."
    docker push "${full_image}" 2>&1 | tee -a "${LOG_FILE}"
    docker push "${ecr_uri}/${ecr_repo}:latest" 2>&1 | tee -a "${LOG_FILE}"

    # Get current task definition
    info "Retrieving current task definition..."
    local task_def_arn
    task_def_arn=$(aws ecs describe-services \
        --cluster "${cluster}" \
        --services "${service}" \
        --query 'services[0].taskDefinition' \
        --output text)

    if [[ -z "${task_def_arn}" ]] || [[ "${task_def_arn}" == "None" ]]; then
        error "Could not find task definition for service '${service}' in cluster '${cluster}'"
        exit 1
    fi

    # Get task definition and update image
    info "Creating new task definition with updated image..."
    local task_def
    task_def=$(aws ecs describe-task-definition \
        --task-definition "${task_def_arn}" \
        --query 'taskDefinition' \
        --output json)

    # Update the container image in the task definition
    local new_task_def
    new_task_def=$(echo "${task_def}" | jq \
        --arg IMAGE "${full_image}" \
        '.containerDefinitions[0].image = $IMAGE |
         del(.taskDefinitionArn, .revision, .status, .requiresAttributes,
             .compatibilities, .registeredAt, .registeredBy)')

    # Register new task definition
    local new_task_def_arn
    new_task_def_arn=$(aws ecs register-task-definition \
        --cli-input-json "${new_task_def}" \
        --query 'taskDefinition.taskDefinitionArn' \
        --output text)

    info "New task definition: ${new_task_def_arn}"

    # Store current task definition for rollback
    PREVIOUS_TASK_DEF="${task_def_arn}"
    export PREVIOUS_TASK_DEF

    # Update service
    info "Updating ECS service..."
    aws ecs update-service \
        --cluster "${cluster}" \
        --service "${service}" \
        --task-definition "${new_task_def_arn}" \
        --force-new-deployment \
        --output json 2>&1 | tee -a "${LOG_FILE}"

    # Wait for deployment to stabilize
    info "Waiting for ECS service to stabilize..."
    wait_for_ecs_deployment "${cluster}" "${service}"

    info "ECS deployment completed successfully!"
}

wait_for_ecs_deployment() {
    local cluster="$1"
    local service="$2"
    local retries=${HEALTH_CHECK_RETRIES}
    local interval=${HEALTH_CHECK_INTERVAL}

    for ((i=1; i<=retries; i++)); do
        local deployment_status
        deployment_status=$(aws ecs describe-services \
            --cluster "${cluster}" \
            --services "${service}" \
            --query 'services[0].deployments' \
            --output json)

        local primary_count
        local running_count
        local desired_count
        primary_count=$(echo "${deployment_status}" | jq '[.[] | select(.status=="PRIMARY")] | length')
        running_count=$(echo "${deployment_status}" | jq '.[0].runningCount')
        desired_count=$(echo "${deployment_status}" | jq '.[0].desiredCount')

        info "Deployment status check ${i}/${retries}: running=${running_count}, desired=${desired_count}"

        if [[ "${running_count}" == "${desired_count}" ]] && [[ "${primary_count}" == "1" ]]; then
            local total_deployments
            total_deployments=$(echo "${deployment_status}" | jq 'length')
            if [[ "${total_deployments}" == "1" ]]; then
                info "Service has stabilized!"
                return 0
            fi
        fi

        sleep "${interval}"
    done

    error "ECS service did not stabilize within the expected time."
    return 1
}

# =============================================================================
# Lambda Deployment
# =============================================================================

deploy_lambda() {
    local function_name="${LAMBDA_FUNCTION}"
    local source_dir="${SOURCE_DIR:-.}"

    if [[ -z "${function_name}" ]]; then
        error "Lambda function name is required. Use --lambda-function option."
        exit 1
    fi

    if [[ ! -d "${source_dir}" ]]; then
        error "Source directory does not exist: ${source_dir}"
        exit 1
    fi

    info "Lambda Deployment Configuration:"
    info "  Function: ${function_name}"
    info "  Source:   ${source_dir}"

    if [[ "${DRY_RUN}" == "true" ]]; then
        info "[DRY RUN] Would deploy to Lambda function '${function_name}'"
        return 0
    fi

    # Check if function exists
    if ! aws lambda get-function --function-name "${function_name}" &>/dev/null; then
        error "Lambda function '${function_name}' does not exist."
        exit 1
    fi

    # Create deployment package
    local zip_file="/tmp/lambda-deploy-${TIMESTAMP}.zip"

    info "Creating deployment package..."
    (cd "${source_dir}" && zip -r "${zip_file}" . -x "*.git*" "*.env*" "*node_modules*" "*.test.*" "*__pycache__*") \
        2>&1 | tee -a "${LOG_FILE}"

    local zip_size
    zip_size=$(du -sh "${zip_file}" | cut -f1)
    info "Deployment package size: ${zip_size}"

    # Publish previous version for rollback
    info "Publishing current version for rollback..."
    local previous_version
    previous_version=$(aws lambda publish-version \
        --function-name "${function_name}" \
        --description "Pre-deploy backup ${TIMESTAMP}" \
        --query 'Version' \
        --output text 2>/dev/null || echo "")

    if [[ -n "${previous_version}" ]]; then
        PREVIOUS_LAMBDA_VERSION="${previous_version}"
        export PREVIOUS_LAMBDA_VERSION
        info "Previous version saved: ${previous_version}"
    fi

    # Check if package is larger than 50MB (direct upload limit)
    local zip_bytes
    zip_bytes=$(stat -f%z "${zip_file}" 2>/dev/null || stat -c%s "${zip_file}" 2>/dev/null)

    if [[ ${zip_bytes} -gt 52428800 ]]; then
        # Upload via S3
        local s3_key="lambda-deployments/${function_name}/${TIMESTAMP}.zip"
        local deploy_bucket="${S3_BUCKET:-lambda-deploy-${AWS_DEFAULT_REGION}}"

        info "Package exceeds 50MB, uploading via S3..."
        aws s3 cp "${zip_file}" "s3://${deploy_bucket}/${s3_key}" 2>&1 | tee -a "${LOG_FILE}"

        aws lambda update-function-code \
            --function-name "${function_name}" \
            --s3-bucket "${deploy_bucket}" \
            --s3-key "${s3_key}" \
            --output json 2>&1 | tee -a "${LOG_FILE}"
    else
        # Direct upload
        info "Updating Lambda function code..."
        aws lambda update-function-code \
            --function-name "${function_name}" \
            --zip-file "fileb://${zip_file}" \
            --output json 2>&1 | tee -a "${LOG_FILE}"
    fi

    # Wait for function to be updated
    info "Waiting for function update to complete..."
    aws lambda wait function-updated \
        --function-name "${function_name}" 2>&1 | tee -a "${LOG_FILE}"

    # Update environment variables with deployment metadata
    info "Updating deployment metadata..."
    aws lambda update-function-configuration \
        --function-name "${function_name}" \
        --environment "Variables={DEPLOY_TIMESTAMP=${TIMESTAMP},DEPLOY_ENVIRONMENT=${ENVIRONMENT},DEPLOY_VERSION=$(get_git_sha)}" \
        --output json 2>&1 | tee -a "${LOG_FILE}"

    # Wait again for configuration update
    aws lambda wait function-updated \
        --function-name "${function_name}" 2>&1 | tee -a "${LOG_FILE}"

    # Publish new version
    info "Publishing new version..."
    local new_version
    new_version=$(aws lambda publish-version \
        --function-name "${function_name}" \
        --description "Deploy ${TIMESTAMP} ($(get_git_sha))" \
        --query 'Version' \
        --output text)
    info "Published version: ${new_version}"

    # Clean up zip file
    rm -f "${zip_file}"

    # Test invocation
    info "Performing test invocation..."
    local invoke_result
    invoke_result=$(aws lambda invoke \
        --function-name "${function_name}" \
        --payload '{"test": true}' \
        --log-type Tail \
        /tmp/lambda-invoke-result.json 2>&1)

    local status_code
    status_code=$(echo "${invoke_result}" | jq -r '.StatusCode // empty' 2>/dev/null || echo "")

    if [[ "${status_code}" == "200" ]]; then
        info "Test invocation successful!"
    else
        warn "Test invocation returned status: ${status_code}"
        warn "This may be expected depending on function configuration."
    fi

    rm -f /tmp/lambda-invoke-result.json

    info "Lambda deployment completed successfully!"
}

# =============================================================================
# CloudFormation Deployment
# =============================================================================

deploy_cloudformation() {
    local stack_name="${STACK_NAME}"
    local template_file="${TEMPLATE_FILE:-template.yaml}"
    local params_file="${PARAMS_FILE:-}"

    if [[ -z "${stack_name}" ]]; then
        error "Stack name is required. Use -s or --stack-name option."
        exit 1
    fi

    if [[ ! -f "${template_file}" ]]; then
        error "CloudFormation template not found: ${template_file}"
        exit 1
    fi

    info "CloudFormation Deployment Configuration:"
    info "  Stack:    ${stack_name}"
    info "  Template: ${template_file}"
    if [[ -n "${params_file}" ]]; then
        info "  Params:   ${params_file}"
    fi

    # Validate template
    info "Validating CloudFormation template..."
    aws cloudformation validate-template \
        --template-body "file://${template_file}" \
        --output json 2>&1 | tee -a "${LOG_FILE}"

    if [[ $? -ne 0 ]]; then
        error "Template validation failed!"
        exit 1
    fi

    if [[ "${DRY_RUN}" == "true" ]]; then
        # Create change set for preview
        local change_set_name="deploy-preview-${TIMESTAMP}"
        info "[DRY RUN] Creating change set for preview..."

        local cf_args=(
            "--stack-name" "${stack_name}"
            "--change-set-name" "${change_set_name}"
            "--template-body" "file://${template_file}"
            "--capabilities" "CAPABILITY_IAM" "CAPABILITY_NAMED_IAM" "CAPABILITY_AUTO_EXPAND"
            "--tags" "Key=Environment,Value=${ENVIRONMENT}" "Key=DeployTimestamp,Value=${TIMESTAMP}"
        )

        if [[ -n "${params_file}" ]] && [[ -f "${params_file}" ]]; then
            cf_args+=("--parameters" "file://${params_file}")
        fi

        # Check if stack exists
        if aws cloudformation describe-stacks --stack-name "${stack_name}" &>/dev/null 2>&1; then
            cf_args+=("--change-set-type" "UPDATE")
        else
            cf_args+=("--change-set-type" "CREATE")
        fi

        aws cloudformation create-change-set "${cf_args[@]}" 2>&1 | tee -a "${LOG_FILE}"

        info "Waiting for change set to be created..."
        aws cloudformation wait change-set-create-complete \
            --stack-name "${stack_name}" \
            --change-set-name "${change_set_name}" 2>&1 || true

        info "Change set details:"
        aws cloudformation describe-change-set \
            --stack-name "${stack_name}" \
            --change-set-name "${change_set_name}" \
            --output table 2>&1 | tee -a "${LOG_FILE}"

        # Clean up change set
        aws cloudformation delete-change-set \
            --stack-name "${stack_name}" \
            --change-set-name "${change_set_name}" 2>/dev/null || true

        return 0
    fi

    # Build deployment arguments
    local deploy_args=(
        "--stack-name" "${stack_name}"
        "--template-file" "${template_file}"
        "--capabilities" "CAPABILITY_IAM" "CAPABILITY_NAMED_IAM" "CAPABILITY_AUTO_EXPAND"
        "--tags" "Environment=${ENVIRONMENT}" "DeployTimestamp=${TIMESTAMP}" "GitSHA=$(get_git_sha)"
        "--no-fail-on-empty-changeset"
    )

    if [[ -n "${params_file}" ]] && [[ -f "${params_file}" ]]; then
        deploy_args+=("--parameter-overrides" "file://${params_file}")
    fi

    if [[ "${ROLLBACK_ON_FAILURE}" == "false" ]]; then
        deploy_args+=("--disable-rollback")
    fi

    # Deploy stack
    info "Deploying CloudFormation stack..."
    aws cloudformation deploy "${deploy_args[@]}" 2>&1 | tee -a "${LOG_FILE}"

    # Show stack outputs
    info "Stack outputs:"
    aws cloudformation describe-stacks \
        --stack-name "${stack_name}" \
        --query 'Stacks[0].Outputs' \
        --output table 2>&1 | tee -a "${LOG_FILE}"

    info "CloudFormation deployment completed successfully!"
}

# =============================================================================
# Elastic Beanstalk Deployment
# =============================================================================

deploy_elastic_beanstalk() {
    local app_name="${EB_APP_NAME:-${STACK_NAME}}"
    local env_name="${EB_ENV_NAME:-${ENVIRONMENT}}"
    local source_dir="${SOURCE_DIR:-.}"

    if [[ -z "${app_name}" ]]; then
        error "Elastic Beanstalk application name is required."
        exit 1
    fi

    info "Elastic Beanstalk Deployment Configuration:"
    info "  Application:  ${app_name}"
    info "  Environment:  ${env_name}"
    info "  Source:       ${source_dir}"

    if [[ "${DRY_RUN}" == "true" ]]; then
        info "[DRY RUN] Would deploy to Elastic Beanstalk application '${app_name}'"
        return 0
    fi

    local version_label="${app_name}-$(get_git_sha)-${TIMESTAMP}"
    local zip_file="/tmp/eb-deploy-${TIMESTAMP}.zip"
    local s3_bucket
    local s3_key="deployments/${app_name}/${version_label}.zip"

    # Get the S3 bucket used by Elastic Beanstalk
    s3_bucket=$(aws elasticbeanstalk create-storage-location --query 'S3Bucket' --output text 2>/dev/null)

    # Create deployment package
    info "Creating deployment package..."
    (cd "${source_dir}" && zip -r "${zip_file}" . -x "*.git*" "*node_modules*" "*.env*") \
        2>&1 | tee -a "${LOG_FILE}"

    # Upload to S3
    info "Uploading deployment package to S3..."
    aws s3 cp "${zip_file}" "s3://${s3_bucket}/${s3_key}" 2>&1 | tee -a "${LOG_FILE}"

    # Create application version
    info "Creating application version: ${version_label}"
    aws elasticbeanstalk create-application-version \
        --application-name "${app_name}" \
        --version-label "${version_label}" \
        --source-bundle "S3Bucket=${s3_bucket},S3Key=${s3_key}" \
        --description "Deployed at ${TIMESTAMP} from $(get_git_branch):$(get_git_sha)" \
        --output json 2>&1 | tee -a "${LOG_FILE}"

    # Update environment
    info "Updating environment: ${env_name}"
    aws elasticbeanstalk update-environment \
        --application-name "${app_name}" \
        --environment-name "${env_name}" \
        --version-label "${version_label}" \
        --output json 2>&1 | tee -a "${LOG_FILE}"

    # Wait for environment to be ready
    info "Waiting for environment to be ready..."
    aws elasticbeanstalk wait environment-updated \
        --application-name "${app_name}" \
        --environment-names "${env_name}" 2>&1 | tee -a "${LOG_FILE}"

    # Check environment health
    local health
    health=$(aws elasticbeanstalk describe-environment-health \
        --environment-name "${env_name}" \
        --attribute-names All \
        --query 'HealthStatus' \
        --output text 2>/dev/null || echo "Unknown")

    info "Environment health: ${health}"

    # Clean up
    rm -f "${zip_file}"

    info "Elastic Beanstalk deployment completed successfully!"
}

# =============================================================================
# Rollback Functions
# =============================================================================

perform_rollback() {
    case "${DEPLOY_TYPE}" in
        ecs)
            rollback_ecs
            ;;
        lambda)
            rollback_lambda
            ;;
        cloudformation)
            rollback_cloudformation
            ;;
        *)
            warn "Automatic rollback not supported for deployment type: ${DEPLOY_TYPE}"
            ;;
    esac
}

rollback_ecs() {
    if [[ -n "${PREVIOUS_TASK_DEF:-}" ]]; then
        warn "Rolling back ECS service to previous task definition: ${PREVIOUS_TASK_DEF}"
        aws ecs update-service \
            --cluster "${ECS_CLUSTER}" \
            --service "${ECS_SERVICE}" \
            --task-definition "${PREVIOUS_TASK_DEF}" \
            --force-new-deployment \
            --output json 2>&1 | tee -a "${LOG_FILE}"
        info "Rollback initiated. Previous task definition restored."
    else
        warn "No previous task definition available for rollback."
    fi
}

rollback_lambda() {
    if [[ -n "${PREVIOUS_LAMBDA_VERSION:-}" ]]; then
        warn "Rolling back Lambda function to version: ${PREVIOUS_LAMBDA_VERSION}"
        # If there's an alias, update it to point to previous version
        aws lambda update-alias \
            --function-name "${LAMBDA_FUNCTION}" \
            --name "live" \
            --function-version "${PREVIOUS_LAMBDA_VERSION}" 2>/dev/null || {
            warn "No 'live' alias found. Manual rollback may be needed."
        }
        info "Lambda rollback initiated."
    else
        warn "No previous Lambda version available for rollback."
    fi
}

rollback_cloudformation() {
    if [[ -n "${STACK_NAME:-}" ]]; then
        warn "CloudFormation handles rollback automatically if --disable-rollback was not set."
        local stack_status
        stack_status=$(aws cloudformation describe-stacks \
            --stack-name "${STACK_NAME}" \
            --query 'Stacks[0].StackStatus' \
            --output text 2>/dev/null || echo "UNKNOWN")
        info "Current stack status: ${stack_status}"

        if [[ "${stack_status}" == *"FAILED"* ]] || [[ "${stack_status}" == *"ROLLBACK"* ]]; then
            warn "Stack is in a failed state. Manual intervention may be required."
        fi
    fi
}

# =============================================================================
# Post-Deployment
# =============================================================================

post_deploy_summary() {
    echo ""
    echo "============================================="
    info "📋 Deployment Summary"
    echo "============================================="
    info "Type:        ${DEPLOY_TYPE}"
    info "Environment: ${ENVIRONMENT}"
    info "Region:      ${AWS_DEFAULT_REGION}"
    info "Timestamp:   ${TIMESTAMP}"
    info "Git SHA:     $(get_git_sha)"
    info "Git Branch:  $(get_git_branch)"
    info "Dry Run:     ${DRY_RUN}"
    info "Log File:    ${LOG_FILE}"
    echo "============================================="
    echo ""
}

# =============================================================================
# Parse Arguments
# =============================================================================

parse_args() {
    SOURCE_DIR=""
    TEMPLATE_FILE=""
    PARAMS_FILE=""
    DOCKER_FILE="./Dockerfile"
    IMAGE_TAG=""
    ENVIRONMENT="${DEPLOY_ENVIRONMENT:-${DEFAULT_ENVIRONMENT}}"
    AWS_REGION="${AWS_DEFAULT_REGION:-${DEFAULT_REGION}}"
    S3_BUCKET="${DEFAULT_S3_BUCKET}"
    ECR_REPO="${DEFAULT_ECR_REPO}"
    ECS_CLUSTER="${DEFAULT_ECS_CLUSTER}"
    ECS_SERVICE="${DEFAULT_ECS_SERVICE}"
    LAMBDA_FUNCTION="${DEFAULT_LAMBDA_FUNCTION}"
    STACK_NAME="${DEFAULT_STACK_NAME}"
    VERBOSE="false"

    while [[ $# -gt 0 ]]; do
        case "$1" in
            -t|--type)
                DEPLOY_TYPE="$2"
                shift 2
                ;;
            -e|--environment)
                ENVIRONMENT="$2"
                shift 2
                ;;
            -r|--region)
                AWS_REGION="$2"
                export AWS_DEFAULT_REGION="$2"
                shift 2
                ;;
            -p|--profile)
                export AWS_PROFILE="$2"
                shift 2
                ;;
            -s|--stack-name)
                STACK_NAME="$2"
                shift 2
                ;;
            -b|--bucket)
                S3_BUCKET="$2"
                shift 2
                ;;
            --ecr-repo)
                ECR_REPO="$2"
                shift 2
                ;;
            --ecs-cluster)
                ECS_CLUSTER="$2"
                shift 2
                ;;
            --ecs-service)
                ECS_SERVICE="$2"
                shift 2
                ;;
            --lambda-function)
                LAMBDA_FUNCTION="$2"
                shift 2
                ;;
            --source-dir)
                SOURCE_DIR="$2"
                shift 2
                ;;
            --template)
                TEMPLATE_FILE="$2"
                shift 2
                ;;
            --params-file)
                PARAMS_FILE="$2"
                shift 2
                ;;
            --docker-file)
                DOCKER_FILE="$2"
                shift 2
                ;;
            --image-tag)
                IMAGE_TAG="$2"
                shift 2
                ;;
            --dry-run)
                DRY_RUN=true
                shift
                ;;
            --force)
                FORCE=true
                shift
                ;;
            --no-rollback)
                ROLLBACK_ON_FAILURE=false
                shift
                ;;
            --verbose)
                VERBOSE=true
                shift
                ;;
            -h|--help)
                usage
                ;;
            *)
                error "Unknown option: $1"
                echo "Use ${SCRIPT_NAME} --help for usage information."
                exit 1
                ;;
        esac
    done

    # Validate deployment type
    if [[ -z "${DEPLOY_TYPE}" ]]; then
        error "Deployment type is required. Use -t or --type option."
        echo "Valid types: s3, ecs, lambda, cloudformation, eb"
        exit 1
    fi

    case "${DEPLOY_TYPE}" in
        s3|ecs|lambda|cloudformation|eb)
            ;;
        *)
            error "Invalid deployment type: ${DEPLOY_TYPE}"
            echo "Valid types: s3, ecs, lambda, cloudformation, eb"
            exit 1
            ;;
    esac

    # Validate environment
    case "${ENVIRONMENT}" in
        dev|staging|production|prod)
            if [[ "${ENVIRONMENT}" == "prod" ]]; then
                ENVIRONMENT="production"
            fi
            ;;
        *)
            warn "Non-standard environment: ${ENVIRONMENT}"
            ;;
    esac
}

# =============================================================================
# Main
# =============================================================================

main() {
    parse_args "$@"

    echo ""
    echo "============================================="
    info "🚀 AWS Deployment Script"
    echo "============================================="
    info "Deployment Type: ${DEPLOY_TYPE}"
    info "Environment:     ${ENVIRONMENT}"
    info "Region:          ${AWS_REGION}"
    info "Dry Run:         ${DRY_RUN}"
    info "CI Environment:  $(is_ci_environment && echo 'Yes' || echo 'No')"
    echo "============================================="
    echo ""

    # Pre-flight checks
    check_prerequisites
    configure_aws_auth

    # Confirmation for production deployments
    if [[ "${ENVIRONMENT}" == "production" ]] && [[ "${DRY_RUN}" == "false" ]]; then
        if ! confirm_action "⚠️  You are about to deploy to PRODUCTION. This action cannot be easily undone."; then
            info "Deployment cancelled."
            exit 0
        fi
    fi

    # Execute deployment
    case "${DEPLOY_TYPE}" in
        s3)
            deploy_s3
            ;;
        ecs)
            deploy_ecs
            ;;
        lambda)
            deploy_lambda
            ;;
        cloudformation)
            deploy_cloudformation
            ;;
        eb)
            deploy_elastic_beanstalk
            ;;
    esac

    # Post-deployment summary
    post_deploy_summary

    info "✅ Deployment completed successfully!"
}

main "$@"